package com.google.gson.internal;
import com.google.gson.FieldAttributes;
import com.google.gson.TypeAdapterFactory;
import com.google.gson.annotations.Expose;
import com.google.gson.annotations.Since;
import com.google.gson.annotations.Until;
import java.util.ArrayList;
import java.util.Collections;
import java.util.List;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.ExclusionStrategy;
import com.google.gson.Gson;
import com.google.gson.TypeAdapter;
import com.google.gson.reflect.TypeToken;
import com.google.gson.stream.JsonReader;
import com.google.gson.stream.JsonWriter;
import java.io.IOException;
import java.lang.reflect.Field;
import java.lang.reflect.Modifier;
import java.lang.reflect.Method;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.ArgumentCaptor;

public class ExcluderTest {

  private Excluder excluder;
  private Gson gsonMock;

  @BeforeEach
  public void setUp() {
    excluder = new Excluder();
    gsonMock = mock(Gson.class);
  }

  @Test
  public void testCreate_NoExclusion_ReturnsNull() {
    TypeToken<String> typeToken = TypeToken.get(String.class);
    // spy on excluder to override excludeClassChecks and excludeClassInStrategy to false
    Excluder spyExcluder = spy(excluder);
    doReturn(false).when(spyExcluder).excludeClassChecks(String.class);
    doReturn(false).when(spyExcluder).excludeClassInStrategy(String.class, true);
    doReturn(false).when(spyExcluder).excludeClassInStrategy(String.class, false);

    TypeAdapter<String> adapter = spyExcluder.create(gsonMock, typeToken);
    assertNull(adapter);
  }

  @Test
  public void testCreate_ExcludeClassSkipSerializeAndDeserialize() throws IOException {
    TypeToken<String> typeToken = TypeToken.get(String.class);
    Excluder spyExcluder = spy(excluder);
    doReturn(true).when(spyExcluder).excludeClassChecks(String.class);
    doReturn(true).when(spyExcluder).excludeClassInStrategy(String.class, true);
    doReturn(true).when(spyExcluder).excludeClassInStrategy(String.class, false);

    // Prepare delegate adapter mock to return a known value
    @SuppressWarnings("unchecked")
    TypeAdapter<String> delegateAdapter = mock(TypeAdapter.class);
    when(delegateAdapter.read(any(JsonReader.class))).thenReturn("delegateRead");
    doNothing().when(delegateAdapter).write(any(JsonWriter.class), any());

    // Setup gson.getDelegateAdapter to return delegateAdapter
    when(gsonMock.getDelegateAdapter(spyExcluder, typeToken)).thenReturn(delegateAdapter);

    TypeAdapter<String> adapter = spyExcluder.create(gsonMock, typeToken);
    assertNotNull(adapter);

    // Use reflection to access the private delegate field and delegate() method
    try {
      JsonReader jsonReaderMock = mock(JsonReader.class);
      JsonWriter jsonWriterMock = mock(JsonWriter.class);

      // read() should skip value and return null because skipDeserialize = true
      adapter.read(jsonReaderMock);
      verify(jsonReaderMock).skipValue();

      // write() should write nullValue because skipSerialize = true
      adapter.write(jsonWriterMock, "anyValue");
      verify(jsonWriterMock).nullValue();

      // Now test when skipSerialize and skipDeserialize are false individually

      // skipDeserialize false, skipSerialize true
      doReturn(true).when(spyExcluder).excludeClassChecks(String.class);
      doReturn(true).when(spyExcluder).excludeClassInStrategy(String.class, true);
      doReturn(false).when(spyExcluder).excludeClassInStrategy(String.class, false);
      adapter = spyExcluder.create(gsonMock, typeToken);
      assertNotNull(adapter);

      JsonReader jsonReaderMock2 = mock(JsonReader.class);
      JsonWriter jsonWriterMock2 = mock(JsonWriter.class);
      when(gsonMock.getDelegateAdapter(spyExcluder, typeToken)).thenReturn(delegateAdapter);

      // read() should delegate read because skipDeserialize = false
      adapter.read(jsonReaderMock2);
      verify(delegateAdapter, atLeastOnce()).read(jsonReaderMock2);

      // write() should write nullValue because skipSerialize = true
      adapter.write(jsonWriterMock2, "value");
      verify(jsonWriterMock2).nullValue();

      // skipDeserialize true, skipSerialize false
      doReturn(true).when(spyExcluder).excludeClassChecks(String.class);
      doReturn(false).when(spyExcluder).excludeClassInStrategy(String.class, true);
      doReturn(true).when(spyExcluder).excludeClassInStrategy(String.class, false);
      adapter = spyExcluder.create(gsonMock, typeToken);
      assertNotNull(adapter);

      JsonReader jsonReaderMock3 = mock(JsonReader.class);
      JsonWriter jsonWriterMock3 = mock(JsonWriter.class);
      when(gsonMock.getDelegateAdapter(spyExcluder, typeToken)).thenReturn(delegateAdapter);

      // read() should skip value because skipDeserialize = true
      adapter.read(jsonReaderMock3);
      verify(jsonReaderMock3, atLeastOnce()).skipValue();

      // write() should delegate write because skipSerialize = false
      adapter.write(jsonWriterMock3, "value");
      verify(delegateAdapter, atLeastOnce()).write(jsonWriterMock3, "value");

    } catch (IOException e) {
      fail("IOException should not be thrown");
    }
  }

  @Test
  public void testCreate_DelegateLazyInitialization() throws Exception {
    TypeToken<String> typeToken = TypeToken.get(String.class);
    Excluder spyExcluder = spy(excluder);
    doReturn(true).when(spyExcluder).excludeClassChecks(String.class);
    doReturn(true).when(spyExcluder).excludeClassInStrategy(String.class, true);
    doReturn(true).when(spyExcluder).excludeClassInStrategy(String.class, false);

    @SuppressWarnings("unchecked")
    TypeAdapter<String> delegateAdapter = mock(TypeAdapter.class);
    when(delegateAdapter.read(any(JsonReader.class))).thenReturn("readValue");
    doNothing().when(delegateAdapter).write(any(JsonWriter.class), any());

    when(gsonMock.getDelegateAdapter(spyExcluder, typeToken)).thenReturn(delegateAdapter);

    TypeAdapter<String> adapter = spyExcluder.create(gsonMock, typeToken);
    assertNotNull(adapter);

    // Use reflection to get the private delegate() method
    Method delegateMethod = adapter.getClass().getDeclaredMethod("delegate");
    delegateMethod.setAccessible(true);

    @SuppressWarnings("unchecked")
    TypeAdapter<String> firstDelegate = (TypeAdapter<String>) delegateMethod.invoke(adapter);
    @SuppressWarnings("unchecked")
    TypeAdapter<String> secondDelegate = (TypeAdapter<String>) delegateMethod.invoke(adapter);

    assertSame(firstDelegate, secondDelegate);
    verify(gsonMock, times(1)).getDelegateAdapter(spyExcluder, typeToken);
  }
}

